 ASX_API ASX_MUST_USE asx_status asx_obligation_transition_check(asx_obligation_state from,
                                                                 asx_obligation_state to);

-/* Returns nonzero if the region state allows spawning new tasks. */
+/* Returns nonzero if the region state allows strict OPEN-only admissions such
+ * as child regions and obligation reservation. */
 ASX_API int asx_region_can_spawn(asx_region_state s);

-/* Returns nonzero if the region state allows new work (spawn, reserve). */
+/* Returns nonzero if the region state allows task admission, including
+ * finalizer-spawned cleanup work during FINALIZING. */
 ASX_API int asx_region_can_accept_work(asx_region_state s);

 /* Returns nonzero if the region is in a closing or draining state. */

@@ -375,8 +375,9 @@ asx_status asx_task_spawn(asx_region_id region, asx_task_poll_fn poll_fn, void *
     if (st != ASX_OK) return st;
     if (r->poisoned) return ASX_E_REGION_POISONED;

-    /* Only open regions can spawn tasks */
-    if (!asx_region_can_spawn(r->state)) return ASX_E_REGION_NOT_OPEN;
+    /* Finalizing regions may still spawn cleanup tasks; broader admissions
+     * like obligations remain OPEN-only. */
+    if (!asx_region_can_accept_work(r->state)) return ASX_E_REGION_NOT_OPEN;

     if (g_task_count >= ASX_MAX_TASKS) return ASX_E_RESOURCE_EXHAUSTED;

@@ -422,7 +423,7 @@ asx_status asx_task_spawn_captured(asx_region_id region, asx_task_poll_fn poll_f

     st = asx_region_slot_lookup(region, &r);
     if (st != ASX_OK) return st;
-    if (!asx_region_can_spawn(r->state)) return ASX_E_REGION_NOT_OPEN;
+    if (!asx_region_can_accept_work(r->state)) return ASX_E_REGION_NOT_OPEN;

     captured = asx_region_capture_alloc(r, state_size, &old_capture_used);
     if (captured == NULL) return ASX_E_RESOURCE_EXHAUSTED;

@@ -27,6 +27,12 @@ static asx_status poll_pending(void *data, asx_task_id self) {
     return ASX_E_PENDING;
 }

+static asx_status poll_complete(void *data, asx_task_id self) {
+    (void)data;
+    (void)self;
+    return ASX_OK;
+}
+
 static asx_status poll_checkpoint_then_complete(void *data, asx_task_id self) {
     asx_checkpoint_result cr;
     (void)data;
@@ -143,6 +149,55 @@ TEST(region_drain_budget_exhaustion_leaves_region_closing) {
     ASSERT_TRUE(region->task_count > 0);
 }

+TEST(finalizing_region_allows_cleanup_task_spawn) {
+    asx_region_id rid;
+    asx_region_slot *region = NULL;
+    asx_task_id tid;
+
+    asx_runtime_reset();
+
+    ASSERT_EQ(asx_region_open(&rid), ASX_OK);
+    ASSERT_EQ(asx_region_slot_lookup(rid, &region), ASX_OK);
+    region->state = ASX_REGION_FINALIZING;
+
+    ASSERT_EQ(asx_task_spawn(rid, poll_complete, NULL, &tid), ASX_OK);
+    ASSERT_EQ(region->task_count, 1u);
+}
+
+TEST(finalizing_region_allows_captured_cleanup_task_spawn) {
+    asx_region_id rid;
+    asx_region_slot *region = NULL;
+    asx_task_id tid;
+    uint32_t *captured = NULL;
+
+    asx_runtime_reset();
+
+    ASSERT_EQ(asx_region_open(&rid), ASX_OK);
+    ASSERT_EQ(asx_region_slot_lookup(rid, &region), ASX_OK);
+    region->state = ASX_REGION_FINALIZING;
+
+    ASSERT_EQ(asx_task_spawn_captured(rid, poll_complete, sizeof(*captured), NULL, &tid,
+                                      (void **)&captured),
+              ASX_OK);
+    ASSERT_TRUE(captured != NULL);
+    ASSERT_EQ(*captured, 0u);
+    ASSERT_EQ(region->task_count, 1u);
+}
+
+TEST(finalizing_region_still_rejects_obligation_reserve) {
+    asx_region_id rid;
+    asx_region_slot *region = NULL;
+    asx_obligation_id oid;
+
+    asx_runtime_reset();
+
+    ASSERT_EQ(asx_region_open(&rid), ASX_OK);
+    ASSERT_EQ(asx_region_slot_lookup(rid, &region), ASX_OK);
+    region->state = ASX_REGION_FINALIZING;
+
+    ASSERT_EQ(asx_obligation_reserve(rid, &oid), ASX_E_REGION_NOT_OPEN);
+}
+
 /* --- New tests covering additional branches --- */

 TEST(quiescence_invalid_handle_returns_not_found) {
